#include <stdio.h>
#include <stdlib.h>

// Global variable (initialized) - stored in Data segment
int global_init = 100;

// Global variable (uninitialized) - stored in BSS segment
int global_uninit;

// Static variable - stored in Data/BSS segment
static int static_var = 200;

void func() {
 // Local variable - stored in Stack segment
 int local_var = 300;

 // Static local variable - stored in Data/BSS segment
 static int static_local = 400;

 // Dynamic memory - stored in Heap segment
 int *heap_var = (int*)malloc(sizeof(int));
 *heap_var = 500;

 printf("Local variable (Stack): %p\n", &local_var);
 printf("Static local (Data/BSS): %p\n", &static_local);
 printf("Heap variable (Heap): %p\n", heap_var);

 free(heap_var);
}

int main() {
 // Local variables in Stack
 int local_main = 10;

 printf("Global initialized (Data): %p\n", &global_init);
 printf("Global uninitialized (BSS): %p\n", &global_uninit);
 printf("Static global (Data/BSS): %p\n", &static_var);
 printf("Local main (Stack): %p\n", &local_main);

 func();

 return 0;
}

#include <stdio.h>
#include <stdlib.h>

// Recursive function causing stack overflow
void recursive_func(int counter) {
 int local_array[1000]; // Each call uses ~4KB stack
 local_array[0] = counter;

 printf("Call %d, address of array: %p\n", counter, local_array);

 recursive_func(counter + 1); // Infinite recursion
}

int main() {
 printf("Starting recursive calls...\n");
 printf("Stack grows downward, so addresses will decrease\n\n");

 // This will eventually crash with stack overflow
 recursive_func(1);

 return 0;
}
/* Output before crash:
Call 1, address of array: 0xbfffef00
Call 2, address of array: 0xbfffdf00 (decreased by 4KB)
Call 3, address of array: 0xbfffcf00 (decreased by 4KB)
...
*/

#include <stdio.h>
#include <stdlib.h>

void memory_leak_example() {
 // Allocate memory on Heap
 int *ptr = (int*)malloc(sizeof(int) * 100);

 if (ptr == NULL) {
 printf("Memory allocation failed\n");
 return;
 }

 // Use the memory
 for (int i = 0; i < 100; i++) {
 ptr[i] = i;
 }

 printf("Memory allocated at: %p\n", ptr);

 // BUG: No free() - memory leak!
 // Should have: free(ptr);

 return; // Memory is now leaked
}

int main() {
 printf("Demonstrating memory leak...\n");

 // Call function multiple times - each call leaks memory
 for (int i = 0; i < 5; i++) {
 memory_leak_example();
 }

 // Allocated memory cannot be reclaimed until program ends
 printf("Memory leaked - only freed when program terminates\n");

 return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
 // Allocate multiple small blocks
 void *ptr1 = malloc(100);
 void *ptr2 = malloc(100);
 void *ptr3 = malloc(100);
 void *ptr4 = malloc(100);

 printf("Initial allocations:\n");
 printf("ptr1: %p\n", ptr1);
 printf("ptr2: %p\n", ptr2);
 printf("ptr3: %p\n", ptr3);
 printf("ptr4: %p\n\n", ptr4);

 // Free alternate blocks - creates fragmentation
 free(ptr1);
 free(ptr3);

 printf("After freeing ptr1 and ptr3 (gaps created):\n");

 // Try to allocate a larger block
 void *ptr5 = malloc(150);
 printf("ptr5 (150 bytes): %p\n", ptr5);

 // May succeed in gaps or need to extend heap
 if (ptr5 == NULL) {
 printf("Allocation failed due to fragmentation\n");
 }

 free(ptr2);
 free(ptr4);
 free(ptr5);

 return 0;
}
/*
Memory layout during fragmentation:
[Allocated][Free][Allocated][Free] <- Fragmented heap
When we need contiguous memory, we may fail
